// GET /api/posts?limit=20&after=<cursor>

/**
 * Encode a compound cursor (created_at, id) as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = {
        // created_at may be a Date object; normalize to ISO so it round-trips.
        createdAt: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64url');
}

/**
 * Decode an opaque cursor back into { createdAt, id }.
 * Throws if the cursor is missing fields or not valid base64/JSON.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }
    if (
        decoded == null ||
        typeof decoded.createdAt !== 'string' ||
        decoded.id == null
    ) {
        throw new Error('Malformed cursor');
    }
    return decoded;
}

async function getPosts(req, res) {
    // Clamp limit to a sane range to avoid abuse / accidental huge queries.
    let limit = parseInt(req.query.limit, 10) || 20;
    if (limit < 1) limit = 1;
    if (limit > 100) limit = 100;

    const after = req.query.after;

    const params = [];
    let whereCursor = '';

    if (after !== undefined) {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor' });
        }

        // Sort is (created_at DESC, id DESC), so "next page" = strictly
        // less than the cursor under that ordering. The row-value comparison
        // (created_at, id) < ($1, $2) expresses the compound condition cleanly
        // and is index-friendly.
        params.push(cursor.createdAt, cursor.id);
        whereCursor = ' AND (created_at, id) < ($1, $2)';
    }

    // LIMIT N+1 trick: ask for one extra row to detect whether more exist.
    params.push(limit + 1);
    const limitParam = `$${params.length}`;

    const sql =
        'SELECT id, title, content, author_id, created_at ' +
        'FROM posts ' +
        'WHERE published = true' + whereCursor + ' ' +
        'ORDER BY created_at DESC, id DESC ' +
        `LIMIT ${limitParam}`;

    const result = await db.query(sql, params);
    const rows = result.rows;

    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

### Notes on the implementation

- **No OFFSET.** Paging is driven entirely by the `(created_at, id) < ($1, $2)` row-value comparison. PostgreSQL evaluates this lexicographically — exactly matching the `ORDER BY created_at DESC, id DESC` — so it correctly handles rows that share the same `created_at`.
- **`id` as a tiebreaker** is what makes the cursor stable when many posts have identical timestamps; without it you'd skip or duplicate rows at page boundaries.
- **Opaque base64 cursor** keeps the client from depending on internal column shape — you can change the cursor's contents later without breaking clients.
- **N+1 trick** avoids a separate "is there a next page?" query; the extra row is sliced off before responding.
- **`base64url`** avoids `+`/`/`/`=` characters that need URL-encoding in the query string. (Plain `base64` works too, but URL-safe is cleaner here.)

For best performance, back this with a matching index:
```sql
CREATE INDEX idx_posts_published_created_id
    ON posts (created_at DESC, id DESC)
    WHERE published = true;
```

### Why cursor-based pagination is superior here

1. **Consistent results under writes.** With `OFFSET`, inserting or deleting posts shifts every row's position, so a user paging through can see duplicates or skip items. A cursor anchors to a specific `(created_at, id)` point, so concurrent inserts at the top don't disturb pages already fetched — important for a feed sorted by `created_at DESC`.

2. **Constant-time deep pagination.** `OFFSET 100000` forces Postgres to scan and discard 100k rows on every request — cost grows linearly with depth. The cursor's `WHERE (created_at, id) < (...)` does an index seek straight to the right position, so page 5,000 costs the same as page 1.

3. **No expensive COUNT.** The original `COUNT(*)` scans the whole table (or index) on every request just to compute `totalPages`. Dropping it removes that cost entirely — and `hasMore` gives clients what they actually need for infinite-scroll/"load more" UIs.

The tradeoff: you lose random access to an arbitrary page number (`?page=42`) and a precise total count — but for a chronological feed, forward/backward cursoring is the natural and more scalable access pattern.

