// ─── Cursor Helpers ────────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque base64 cursor string.
 * created_at may be a Date object or an ISO string (pg returns Date by default).
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({
        // Normalize to ISO string so the cursor is always a plain string,
        // not a Date-object representation that may vary by serializer.
        created_at: created_at instanceof Date ? created_at.toISOString() : created_at,
        id,
    });
    return Buffer.from(payload, 'utf8').toString('base64');
}

/**
 * Decodes a base64 cursor string back into { created_at, id }.
 * Returns null if the cursor is missing, malformed, or structurally invalid
 * so the caller can return a 400 immediately.
 */
function decodeCursor(cursor) {
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        const parsed = JSON.parse(json);

        const id = Number.isInteger(parsed.id) ? parsed.id : parseInt(parsed.id, 10);
        const ts = new Date(parsed.created_at);

        // Reject anything that doesn't round-trip cleanly.
        if (!Number.isFinite(id) || id <= 0 || isNaN(ts.getTime())) {
            return null;
        }

        return { created_at: ts.toISOString(), id };
    } catch {
        // JSON.parse failure, base64 garbage, etc.
        return null;
    }
}

// ─── Endpoint ──────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // Clamp limit to a safe maximum so a single request can't hammer the DB.
    const limit = Math.min(parseInt(req.query.limit) || 20, 100);

    // ── Decode cursor (if provided) ────────────────────────────────────────────
    let cursor = null;
    if (req.query.after) {
        cursor = decodeCursor(req.query.after);
        if (!cursor) {
            return res.status(400).json({
                error: 'Invalid cursor. The "after" parameter is malformed or expired.',
            });
        }
    }

    // ── Build and run query ────────────────────────────────────────────────────
    //
    // Compound row-value comparison (PostgreSQL syntax):
    //
    //   (created_at, id) < ($1, $2)
    //
    // is exactly equivalent to:
    //
    //   created_at < $1  OR  (created_at = $1 AND id < $2)
    //
    // This correctly pages through an ORDER BY created_at DESC, id DESC result
    // set: "give me rows whose sort key is strictly less than the cursor's sort key."
    //
    // Fetch limit + 1 rows. If we get that extra row, more pages exist — we just
    // don't return it to the client.

    let result;
    if (cursor) {
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1::timestamptz, $2::int)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]
        );
    } else {
        // First page — no cursor filter at all.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
    }

    // ── Apply N+1 trick ────────────────────────────────────────────────────────
    const hasMore = result.rows.length > limit;
    const posts   = hasMore ? result.rows.slice(0, limit) : result.rows;

    // Build the next cursor from the last row we're actually returning.
    const lastPost    = posts[posts.length - 1] ?? null;
    const nextCursor  = hasMore && lastPost
        ? encodeCursor(lastPost.created_at, lastPost.id)
        : null;

    // ── Respond ────────────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null on the last page
            limit,
        },
    });
}
```

---

## Why cursor-based pagination is superior here

| Concern | Offset | Cursor |
|---|---|---|
| **Stability under writes** | A new post inserted before page 2 is fetched shifts every subsequent row, causing duplicates or skipped rows | The cursor pins to a specific row; inserts/deletes elsewhere don't affect the traversal |
| **Performance at depth** | `OFFSET 10000` forces PostgreSQL to read and discard 10,000 rows on every request — O(n) cost | The `WHERE (created_at, id) < (...)` clause seeks directly to the right position via the index — O(log n) |
| **COUNT(*) cost** | Requires a full table scan for `totalCount` on every request | Eliminated entirely; `hasMore` is O(0) extra cost via the N+1 trick |
| **Scalability** | Degrades linearly as the table grows | Stays constant regardless of table size, provided the index exists |

**One required index** — add this if it doesn't already exist, or the WHERE clause will scan the whole table:

```sql
CREATE INDEX CONCURRENTLY idx_posts_cursor
    ON posts (created_at DESC, id DESC)
    WHERE published = true;
```

The partial index (`WHERE published = true`) matches the query's filter exactly and keeps it lean. With this index in place, every page fetch is a single index range scan with a hard `LIMIT`, no matter how many millions of rows are in the table.

